set-variable.value:
@{
            var body = context.Request.Body.As<JObject>(preserveContent: true);
            var messages = (JArray)body["messages"];
            if (messages == null || messages.Count == 0) return string.Empty;
            // Concatenate all user messages (cap at 9_500 chars for the CS limit)
            var sb = new System.Text.StringBuilder();
            foreach (var m in messages) {
                if ((string)m["role"] == "user") {
                    if (sb.Length > 0) sb.Append('\n');
                    sb.Append((string)m["content"]);
                }
            }
            var s = sb.ToString();
            return s.Length > 9500 ? s.Substring(0, 9500) : s;
        }

send-request.set-body:
@{
                var prompt = (string)context.Variables["userPrompt"];
                return new JObject(new JProperty("userPrompt", prompt)).ToString();
            }

when.condition:
@{
                var resp = (IResponse)context.Variables["csResponse"];
                if (resp.StatusCode != 200) return false;
                var body = resp.Body.As<JObject>(preserveContent: true);
                var det = body.SelectToken("userPromptAnalysis.attackDetected");
                return det != null && (bool)det;
            }

send-request.set-body:
@{
                var prompt = (string)context.Variables["userPrompt"];
                return new JObject(
                    new JProperty("text", prompt),
                    new JProperty("categories", new JArray("Hate", "Violence", "Sexual", "SelfHarm")),
                    new JProperty("outputType", "EightSeverityLevels")
                ).ToString();
            }

when.condition:
@{
                var r = (IResponse)context.Variables["csAnalyze"];
                if (r == null || r.StatusCode != 200) return false;
                var b = r.Body.As<JObject>(preserveContent: true);
                var cats = b["categoriesAnalysis"] as JArray;
                if (cats == null) return false;
                foreach (var c in cats) {
                    if ((int)c["severity"] >= 4) return true;
                }
                return false;
            }
